import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.BbQrW5_t.js";const u=JSON.parse('{"title":"第八章 中学班级管理与教师心理","description":"","frontmatter":{"title":"第八章 中学班级管理与教师心理","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter8.md","filePath":"study/teacher-cert/education-knowledge/chapter8.md","lastUpdated":1783652711000}'),l={name:"study/teacher-cert/education-knowledge/chapter8.md"};function i(h,t,o,n,b,s){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第八章-中学班级管理与教师心理" tabindex="-1">第八章 中学班级管理与教师心理 <a class="header-anchor" href="#第八章-中学班级管理与教师心理" aria-label="Permalink to &quot;第八章 中学班级管理与教师心理&quot;">​</a></h1><blockquote><p>本章考情：选择题为主，约 6-8 分 重点：班集体建设、课堂管理、教师成长阶段</p></blockquote><hr><h2 id="_8-1-班级管理-🔴🔴" tabindex="-1">8.1 班级管理 🔴🔴 <a class="header-anchor" href="#_8-1-班级管理-🔴🔴" aria-label="Permalink to &quot;8.1 班级管理 🔴🔴&quot;">​</a></h2><h3 id="班集体-🔴🔴" tabindex="-1">班集体 🔴🔴 <a class="header-anchor" href="#班集体-🔴🔴" aria-label="Permalink to &quot;班集体 🔴🔴&quot;">​</a></h3><p><strong>班集体的基本特征</strong> 🔴🔴：</p><ol><li>明确的共同目标 — 奋斗方向</li><li>一定的组织结构 — 核心队伍（班干部）</li><li>一定的共同生活准则 — 规章制度</li><li>集体成员之间平等、心理相容 — 舆论氛围</li></ol><p><strong>班集体的形成阶段</strong> 🔴：</p><table tabindex="0"><thead><tr><th>阶段</th><th>特点</th></tr></thead><tbody><tr><td>组建阶段</td><td>依赖教师，松散</td></tr><tr><td>核心形成阶段</td><td>骨干出现，凝聚力增强 🔴</td></tr><tr><td>发展阶段</td><td>自我管理，舆论形成</td></tr><tr><td>成熟阶段</td><td>自觉遵守，共同进步</td></tr></tbody></table><h3 id="班主任工作-🔴" tabindex="-1">班主任工作 🔴 <a class="header-anchor" href="#班主任工作-🔴" aria-label="Permalink to &quot;班主任工作 🔴&quot;">​</a></h3><p><strong>班主任工作内容</strong>：</p><ol><li>了解和研究学生 — 前提 🔴</li><li>组织和培养班集体 — 中心任务 🔴🔴</li><li>协调校内外各种教育力量</li><li>班级日常管理</li><li>做好个别教育工作</li><li>做好学生操行评定</li></ol><p><strong>班主任了解学生的方法</strong> 🔴：</p><ul><li>观察法 — 最基本的方法 🔴</li><li>谈话法</li><li>书面材料分析法</li><li>问卷法</li></ul><hr><h2 id="_8-2-课堂管理-🔴" tabindex="-1">8.2 课堂管理 🔴 <a class="header-anchor" href="#_8-2-课堂管理-🔴" aria-label="Permalink to &quot;8.2 课堂管理 🔴&quot;">​</a></h2><h3 id="群体动力-🔴" tabindex="-1">群体动力 🔴 <a class="header-anchor" href="#群体动力-🔴" aria-label="Permalink to &quot;群体动力 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>含义</th><th>教育启示</th></tr></thead><tbody><tr><td>群体凝聚力</td><td>群体对成员的吸引力</td><td>增强凝聚力提高学习效率</td></tr><tr><td>群体规范</td><td>群体成员共同遵守的行为准则</td><td>制定合理的班规</td></tr><tr><td>课堂气氛</td><td>课堂中的情感状态</td><td>营造积极和谐的课堂氛围</td></tr><tr><td>人际关系</td><td>师生、生生关系</td><td>建立良好师生关系</td></tr></tbody></table><h3 id="课堂纪律-🔴🔴" tabindex="-1">课堂纪律 🔴🔴 <a class="header-anchor" href="#课堂纪律-🔴🔴" aria-label="Permalink to &quot;课堂纪律 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>含义</th><th>形成方式</th></tr></thead><tbody><tr><td>教师促成的纪律</td><td>教师要求下形成的</td><td>教师监督指导</td></tr><tr><td>集体促成的纪律</td><td>同辈群体压力下形成的</td><td>同伴影响</td></tr><tr><td>任务促成的纪律</td><td>为完成特定任务而遵守</td><td>任务驱动</td></tr><tr><td>自我促成的纪律 🔴</td><td>学生自觉遵守</td><td>内化自律（最高级）</td></tr></tbody></table><h3 id="课堂问题行为-🔴" tabindex="-1">课堂问题行为 🔴 <a class="header-anchor" href="#课堂问题行为-🔴" aria-label="Permalink to &quot;课堂问题行为 🔴&quot;">​</a></h3><p><strong>分类</strong>：</p><ul><li>品行性问题行为 — 攻击、破坏</li><li>性格性问题行为 — 孤僻、退缩</li><li>情绪上、社会上的不适应行为</li></ul><p><strong>处理原则</strong>：</p><ol><li>预防为主</li><li>非言语暗示优先</li><li>最小干预原则 🔴</li><li>就事论事，不翻旧账</li></ol><hr><h2 id="_8-3-课外校外教育-🔴" tabindex="-1">8.3 课外校外教育 🔴 <a class="header-anchor" href="#_8-3-课外校外教育-🔴" aria-label="Permalink to &quot;8.3 课外校外教育 🔴&quot;">​</a></h2><h3 id="特点-🔴" tabindex="-1">特点 🔴 <a class="header-anchor" href="#特点-🔴" aria-label="Permalink to &quot;特点 🔴&quot;">​</a></h3><ol><li>自愿性 — 学生自主选择 🔴</li><li>自主性 — 学生主动参与</li><li>灵活性 — 形式多样</li><li>实践性 — 亲身体验</li></ol><h3 id="形式" tabindex="-1">形式 <a class="header-anchor" href="#形式" aria-label="Permalink to &quot;形式&quot;">​</a></h3><ol><li>群众性活动 — 讲座、比赛</li><li>小组活动 — 兴趣小组 🔴（最普遍的形式）</li><li>个人活动 — 个别指导</li></ol><hr><h2 id="_8-4-教师心理-🔴🔴" tabindex="-1">8.4 教师心理 🔴🔴 <a class="header-anchor" href="#_8-4-教师心理-🔴🔴" aria-label="Permalink to &quot;8.4 教师心理 🔴🔴&quot;">​</a></h2><h3 id="教师成长阶段-🔴🔴🔴" tabindex="-1">教师成长阶段 🔴🔴🔴 <a class="header-anchor" href="#教师成长阶段-🔴🔴🔴" aria-label="Permalink to &quot;教师成长阶段 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>关注焦点</th><th>特点</th></tr></thead><tbody><tr><td>关注生存阶段 🔴</td><td>别人怎么看我</td><td>想被认可、被喜欢</td></tr><tr><td>关注情境阶段</td><td>教学情境</td><td>关注课怎么上好</td></tr><tr><td>关注学生阶段 🔴🔴</td><td>学生发展</td><td>因材施教、关注差异</td></tr></tbody></table><h3 id="教师专业发展-🔴" tabindex="-1">教师专业发展 🔴 <a class="header-anchor" href="#教师专业发展-🔴" aria-label="Permalink to &quot;教师专业发展 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>特点</th></tr></thead><tbody><tr><td>新手教师</td><td>严格遵守规则，缺乏灵活性</td></tr><tr><td>高级新手</td><td>能处理简单情境</td></tr><tr><td>胜任者</td><td>能有效教学，有明确目标</td></tr><tr><td>精通者</td><td>教学直觉强，灵活应变</td></tr><tr><td>专家教师</td><td>自动化，举重若轻</td></tr></tbody></table><p><strong>新手与专家教师对比</strong> 🔴：</p><table tabindex="0"><thead><tr><th>维度</th><th>新手教师</th><th>专家教师</th></tr></thead><tbody><tr><td>课前准备</td><td>关注细节，写详细教案</td><td>关注整体，灵活预案</td></tr><tr><td>课堂教学</td><td>按部就班</td><td>灵活应变</td></tr><tr><td>课后反思</td><td>关注自己表现</td><td>关注学生学习效果</td></tr><tr><td>课堂规则</td><td>事后制定</td><td>事先建立</td></tr></tbody></table><h3 id="教师心理健康-🔴" tabindex="-1">教师心理健康 🔴 <a class="header-anchor" href="#教师心理健康-🔴" aria-label="Permalink to &quot;教师心理健康 🔴&quot;">​</a></h3><p><strong>职业倦怠</strong> 🔴🔴：</p><table tabindex="0"><thead><tr><th>维度</th><th>表现</th></tr></thead><tbody><tr><td>情绪衰竭 🔴</td><td>疲惫、缺乏热情</td></tr><tr><td>去个性化</td><td>冷漠、疏远学生</td></tr><tr><td>低个人成就感</td><td>觉得工作没意义</td></tr></tbody></table><p><strong>职业倦怠的应对</strong> 🔴：</p><ol><li>社会支持</li><li>改善工作环境</li><li>自我调节与成长</li><li>建立合理期望</li></ol><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>要点</th></tr></thead><tbody><tr><td>班集体特征</td><td>目标+组织+制度+心理相容</td></tr><tr><td>班主任中心任务</td><td>组织培养班集体</td></tr><tr><td>了解学生基本方法</td><td>观察法</td></tr><tr><td>课堂纪律四类型</td><td>教师促成→集体促成→任务促成→自我促成（由低到高）</td></tr><tr><td>教师成长三阶段</td><td>关注生存→关注情境→关注学生</td></tr><tr><td>职业倦怠三维度</td><td>情绪衰竭+去个性化+低成就感</td></tr></tbody></table>',47)])])}const p=d(l,[["render",i]]);export{u as __pageData,p as default};
